const newsSources = [
  {
    name: "Press Information Bureau",
    abbr: "PIB",
    color: "from-[#0a2a6e] to-[#1a4080]",
  },
  {
    name: "Doordarshan News",
    abbr: "DD",
    color: "from-[#e31e24] to-[#c9191f]",
  },
  {
    name: "News on Air",
    abbr: "AIR",
    color: "from-[#138808] to-[#0d6b06]",
  },
];

const spotlightItems = [
  {
    month: "June 2026",
    title: "Gyan Bharatam Mission",
  },
  {
    month: "May 2026",
    title: "Census of India 2027",
  },
  {
    month: "April 2026",
    title: "Pradhan Mantri Viksit Bharat Rozgar Yojana",
  },
  {
    month: "March 2026",
    title: "Bal Vivah Mukt Bharat",
  },
];

export default function NewsSection() {
  return (
    <section id="news" className="bg-[#f4f6f9] py-14 sm:py-20">
      <div className="mx-auto max-w-[1200px] px-4 sm:px-6">
        <div className="grid gap-12 lg:grid-cols-2 lg:gap-10">
          <div>
            <h2 className="text-2xl font-bold text-gray-900 sm:text-[1.75rem]">
              News / Press Release
            </h2>
            <p className="mt-1 text-sm text-gray-500 sm:text-[15px]">
              Your Gateway to Authentic News
            </p>

            <div className="mt-8 grid gap-4 sm:grid-cols-3">
              {newsSources.map((source) => (
                <article
                  key={source.name}
                  className="group cursor-pointer overflow-hidden rounded-xl border border-gray-100 bg-[#eef0f3] transition-all duration-300 hover:-translate-y-1 hover:shadow-md"
                >
                  <div
                    className={`flex h-28 items-center justify-center bg-gradient-to-br ${source.color} sm:h-32`}
                  >
                    <span className="text-2xl font-bold tracking-wider text-white">
                      {source.abbr}
                    </span>
                  </div>
                  <div className="px-3 py-4 text-center">
                    <h3 className="text-xs font-bold leading-snug text-gray-900 sm:text-[13px]">
                      {source.name}
                    </h3>
                  </div>
                </article>
              ))}
            </div>
          </div>

          <div>
            <h2 className="text-2xl font-bold text-gray-900 sm:text-[1.75rem]">
              Spotlight
            </h2>
            <p className="mt-1 text-sm text-gray-500 sm:text-[15px]">
              Stories from the Core of Our Nation
            </p>

            <div className="mt-8 grid gap-6 lg:grid-cols-[1fr_1fr]">
              <article className="overflow-hidden rounded-xl border border-gray-100 bg-white shadow-sm">
                <div className="relative flex h-44 items-end bg-gradient-to-br from-[#0a2a6e] to-[#2b5ea8] p-5 sm:h-48">
                  <div className="absolute right-4 top-4 h-12 w-12 rounded-full border border-white/30 bg-white/10" aria-hidden="true" />
                  <p className="relative text-xs font-medium uppercase tracking-wider text-white/70">
                    Ministry of Social Justice &amp; Empowerment
                  </p>
                </div>
                <div className="bg-[#e31e24] p-5 text-white">
                  <p className="text-sm font-semibold">July 2026</p>
                  <h3 className="mt-2 text-sm font-bold leading-snug sm:text-[15px]">
                    Pradhan Mantri Anusuchit Jaati Abhyuday Yojana (PM-AJAY)
                  </h3>
                  <p className="mt-2 text-xs leading-relaxed text-white/85">
                    Comprehensive development programme for Scheduled Castes.
                  </p>
                </div>
              </article>

              <div className="divide-y divide-gray-100 rounded-xl border border-gray-100 bg-white shadow-sm">
                {spotlightItems.map((item) => (
                  <article
                    key={item.title}
                    className="group cursor-pointer px-5 py-4 transition-colors hover:bg-gray-50"
                  >
                    <p className="text-xs text-gray-400">{item.month}</p>
                    <h3 className="mt-1 text-sm font-bold text-gray-900 transition-colors group-hover:text-[#0a2a6e] sm:text-[15px]">
                      {item.title}
                    </h3>
                  </article>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}
